name: Issue Validator

on:
  issues:
    types: [opened, edited]

jobs:
  validate:
    runs-on: ubuntu-latest
    permissions:
      issues: write
    steps:
      - name: Validate Issue Quality
        uses: actions/github-script@v7
        with:
          script: |
            const issue = context.payload.issue;
            const body = issue.body || '';

            // --- Configuration ---
            const MIN_DESCRIPTION_LENGTH = 20;
            const MIN_STEPS_LENGTH = 30;
            const VERSION_PATTERN = /^\d+\.\d+\.\d+$/;

            // --- Parsing Logic ---
            function extractSection(text, headerPattern) {
              const match = text.match(new RegExp(`${headerPattern}\\s+([\\s\\S]*?)(?=\\n###|$)`));
              return match ? match[1].trim() : '';
            }

            // Skip validation if it's not a bug report
            const isBugReport = !!body.match(/### 📦 扩展版本 \| Extension Version/);
            if (!isBugReport) return;

            const version = extractSection(body, '### 📦 扩展版本 \\| Extension Version');
            const description = extractSection(body, '### 🐛 问题描述 \\| Bug Description');
            const steps = extractSection(body, '### 📷 复现步骤 \\| Recurrence Steps');

            // --- Validation Logic ---
            let failureReasons = [];

            // 1. Version: must be present and match semver format
            if (!version || !VERSION_PATTERN.test(version)) {
              failureReasons.push('Extension version is missing or invalid (expected format: `x.y.z`).');
            }

            // 2. Bug description: must be present and meaningful
            if (!description || description.length < MIN_DESCRIPTION_LENGTH) {
              failureReasons.push(`Bug description is too short (minimum ${MIN_DESCRIPTION_LENGTH} characters). Please describe the issue clearly.`);
            }

            // 3. Reproduction steps: must be present and detailed enough
            if (!steps || steps.length < MIN_STEPS_LENGTH) {
              failureReasons.push(`Reproduction steps are too short (minimum ${MIN_STEPS_LENGTH} characters). Please provide clear step-by-step instructions to reproduce the bug.`);
            }

            // --- Action ---
            if (failureReasons.length > 0) {
              const reasonList = failureReasons.map(r => `- ${r}`).join('\n');
              console.log(`Closing issue #${issue.number}:\n${reasonList}`);

              // 1. Close as not planned
              await github.rest.issues.update({
                owner: context.repo.owner,
                repo: context.repo.repo,
                issue_number: issue.number,
                state: 'closed',
                state_reason: 'not_planned'
              });

              // 2. Add 'invalid' label
              await github.rest.issues.addLabels({
                owner: context.repo.owner,
                repo: context.repo.repo,
                issue_number: issue.number,
                labels: ['invalid']
              });

              // 3. Post comment
              const comment = `❌ **Issue Closed: Incomplete Bug Report**

This issue was automatically closed because it does not meet the minimum quality requirements.

**Issues found:**
${reasonList}

**To reopen**, please edit your issue to fix the above problems. The validator will re-check automatically.

> Tip: A good bug report includes the exact extension version, a clear description of what went wrong, and detailed step-by-step reproduction instructions.`;

              await github.rest.issues.createComment({
                owner: context.repo.owner,
                repo: context.repo.repo,
                issue_number: issue.number,
                body: comment
              });
            }

